import { Injectable } from '@angular/core';
import { HttpClient, HttpHeaders } from '@angular/common/http';
import { Character, CharacterListItem } from '../models/character';
import { Observable, catchError, tap, throwError } from 'rxjs';
import { AuthService } from './auth.service';

@Injectable({
  providedIn: 'root'
})
export class CharacterService {
  private baseUrl = 'https://characters.discloud.app/api';

  constructor(
    private http: HttpClient,
    private authService: AuthService
  ) { }

  // Método privado para obter os headers de autorização
  private getAuthHeaders(): HttpHeaders {
    const token = localStorage.getItem('auth_token');
    return new HttpHeaders({
      'Content-Type': 'application/json',
      'Authorization': `Bearer ${token}`
    });
  }

  // Método para sanitizar os dados do personagem
  private sanitizeCharacterData(character: Character): any {
    // Cria uma cópia do personagem
    const sanitized = { ...character };

    // Garante que arrays estejam inicializados corretamente
    if (!Array.isArray(sanitized.proficiencies.savingThrows)) sanitized.proficiencies.savingThrows = [];
    if (!Array.isArray(sanitized.proficiencies.skills)) sanitized.proficiencies.skills = [];
    if (!Array.isArray(sanitized.proficiencies.languages)) sanitized.proficiencies.languages = [];
    if (!Array.isArray(sanitized.proficiencies.tools)) sanitized.proficiencies.tools = [];
    if (!Array.isArray(sanitized.proficiencies.weapons)) sanitized.proficiencies.weapons = [];
    if (!Array.isArray(sanitized.proficiencies.armors)) sanitized.proficiencies.armors = [];
    if (!Array.isArray(sanitized.equipment)) sanitized.equipment = [];
    if (!Array.isArray(sanitized.features)) sanitized.features = [];

    // Tratamento das datas para requisição
    const result = {
      ...sanitized,
      createdAt: new Date().toISOString(),
      updatedAt: new Date().toISOString()
    };

    // Garante que valores numéricos sejam números
    result.level = Number(result.level) || 1;
    result.experience = Number(result.experience) || 0;
    result.attributes.strength = Number(result.attributes.strength) || 10;
    result.attributes.dexterity = Number(result.attributes.dexterity) || 10;
    result.attributes.constitution = Number(result.attributes.constitution) || 10;
    result.attributes.intelligence = Number(result.attributes.intelligence) || 10;
    result.attributes.wisdom = Number(result.attributes.wisdom) || 10;
    result.attributes.charisma = Number(result.attributes.charisma) || 10;
    result.hitPoints.maximum = Number(result.hitPoints.maximum) || 10;
    result.hitPoints.current = Number(result.hitPoints.current) || 10;
    result.hitPoints.temporary = Number(result.hitPoints.temporary) || 0;
    result.armorClass = Number(result.armorClass) || 10;
    result.initiative = Number(result.initiative) || 0;
    result.speed = Number(result.speed) || 30;

    return result;
  }

  // Cria um novo personagem
  createCharacter(character: Character): Observable<any> {
    // Adiciona userId do usuário logado
    character.userId = this.authService.getUserId();
    
    // Sanitiza os dados do personagem
    const characterToSend = this.sanitizeCharacterData(character);
    
    // Log para depuração
    console.log('Enviando personagem para API:', JSON.stringify(characterToSend));
    
    return this.http.post(`${this.baseUrl}/personagens`, characterToSend, {
      headers: this.getAuthHeaders()
    }).pipe(
      tap(response => console.log('Resposta da API:', response)),
      catchError(error => {
        console.log('Erro detalhado da API:', error);
        if (error.error && error.error.message) {
          console.log('Mensagem de erro do servidor:', error.error.message);
        }
        return throwError(() => error);
      })
    );
  }

  // Lista todos os personagens do usuário logado
  listCharacters(): Observable<CharacterListItem[]> {
    const userId = this.authService.getUserId();
    return this.http.get<CharacterListItem[]>(`${this.baseUrl}/personagens?userId=${userId}`, {
      headers: this.getAuthHeaders()
    });
  }

  // Obtém um personagem específico
  getCharacter(id: string): Observable<Character> {
    return this.http.get<Character>(`${this.baseUrl}/personagens/${id}`, {
      headers: this.getAuthHeaders()
    });
  }

  // Atualiza um personagem existente
  updateCharacter(id: string, data: Partial<Character>): Observable<any> {
    // Prepara os dados para atualização
    const dataToSend = {
      ...data,
      updatedAt: new Date().toISOString()
    };
    
    // Remove a propriedade updatedAt do tipo Date do objeto original
    delete dataToSend.updatedAt;
    
    // Adiciona a versão string da data
    const finalData = {
      ...dataToSend,
      updatedAt: new Date().toISOString()
    };
    
    return this.http.put(`${this.baseUrl}/personagens/${id}`, finalData, {
      headers: this.getAuthHeaders()
    });
  }

  // Exclui um personagem
  deleteCharacter(id: string): Observable<any> {
    return this.http.delete(`${this.baseUrl}/personagens/${id}`, {
      headers: this.getAuthHeaders()
    });
  }

  // Calcula o bônus de atributo com base no valor
  calculateAttributeModifier(attributeValue: number): number {
    return Math.floor((attributeValue - 10) / 2);
  }

  // Calcula o bônus de proficiência com base no nível
  calculateProficiencyBonus(level: number): number {
    return Math.ceil(1 + (level / 4));
  }
}
